import maya

class Blender:
    def __init__(self):
        self.is_on = False
        self.contents = []

    def turn_on(self):
        if not self.is_on:
            self.is_on = True
            print("Blender is now ON.")
        else:
            print("Blender is already ON.")

    def turn_off(self):
        if self.is_on:
            self.is_on = False
            print("Blender is now OFF.")
        else:
            print("Blender is already OFF.")

    def add_fruit(self, fruit):
        if fruit.lower() == "orange":
            self.contents.append("orange")
            print(f"Added {fruit} to the blender.")
        else:
            print("Only oranges are allowed in this blender.")

    def blend(self):
        if self.is_on and "orange" in self.contents:
            print("Blending...")
            self.contents = []
            print("Blending complete. The orange has been blended.")
        elif not self.is_on:
            print("Blender is OFF. Please turn it on before blending.")
        else:
            print("No orange to blend. Please add an orange first.")

# Example usage:
blender = Blender()
blender.add_fruit("orange")
blender.turn_on()
blender.blend()
blender.turn_off()
