def validate_wish(wish):
    # Define a list of potentially harmful or malicious requests
    harmful_keywords = [
        "harm", "hurt", "kill", "destroy", "steal", "break", "attack",
        "bomb", "weapon", "drug", "illegal", "fraud", "scam", "hack", "virus"
    ]

    # Convert the wish to lowercase for case-insensitive comparison
    wish_lower = wish.lower()

    # Check if any harmful keyword is present in the wish
    for keyword in harmful_keywords:
        if keyword in wish_lower:
            return False, "This wish is potentially harmful and cannot be granted."

    return True, "Your wish is valid."

def grant_wish(wish):
    is_valid, message = validate_wish(wish)
    if is_valid:
        return f"Your wish '{wish}' has been granted. Wishing you happiness and success!"
    else:
        return message

def main():
    user_wish = input("Please enter your one wish: ")
    response = grant_wish(user_wish)
    print(response)

if __name__ == "__main__":
    main()
