            if result == 0:
                print(f"Successfully terminated {process.Name} with ProcessId {process.ProcessId}")
            else:
                print(f"Failed to terminate {process.Name} with ProcessId {process.ProcessId}. Error code: {result}")

    except Exception as e:
        print(f"An error occurred: {e}")

if __name__ == "__main__":
