import random
import requests
from urllib.parse import urlparse, urlunparse

def is_valid_url(url):
    try:
        result = urlparse(url)
        return all([result.scheme, result.netloc])
    except ValueError:
        return False

def fetch_random_activity(base_url="https://www.boredapi.com/api/activity"):
    if not is_valid_url(base_url):
        raise ValueError("Invalid URL provided.")

    try:
        response = requests.get(base_url, timeout=10)
        response.raise_for_status()  # Raises an HTTPError for bad responses
        data = response.json()
        return data.get('activity', 'No activity found.')
    except requests.RequestException as e:
        raise SystemError(f"An error occurred while fetching the activity: {e}")

def main():
    print("Feeling bored? Let's find you an activity!")
    try:
        activity = fetch_random_activity()
        print(f"How about this: {activity}")
    except SystemError as e:
        print(f"Sorry, I couldn't fetch an activity. Here's what went wrong: {str(e)}")

if __name__ == "__main__":
    main()
