def add(a, b):
    return a + b

def subtract(a, b):
    return a - b

def multiply(a, b):
    return a * b

def divide(a, b):
    if b == 0:
        raise ValueError("Cannot divide by zero.")
    return a / b

def factorial(n):
    if n < 0:
        raise ValueError("Factorial is not defined for negative numbers.")
    if n == 0 or n == 1:
        return 1
    result = 1
    for i in range(2, n + 1):
        result *= i
    return result

def fibonacci(n):
    if n <= 0:
        raise ValueError("Fibonacci sequence is not defined for non-positive integers.")
    if n == 1:
        return 0
    if n == 2:
        return 1

    a, b = 0, 1
    for _ in range(2, n):
        a, b = b, a + b
    return b

def is_prime(n):
    if n <= 1:
        return False
    if n <= 3:
        return True
    if n % 2 == 0 or n % 3 == 0:
        return False
    i = 5
    while i * i <= n:
        if n % i == 0 or n % (i + 2) == 0:
            return False
        i += 6
    return True

def gcd(a, b):
    while b:
        a, b = b, a % b
    return a

def lcm(a, b):
    return abs(a * b) // gcd(a, b)

def power(base, exponent):
    return base ** exponent

def sqrt(x):
    if x < 0:
        raise ValueError("Cannot compute the square root of a negative number.")
    return x ** 0.5

def log(base, x):
    if base <= 1:
        raise ValueError("Logarithm base must be greater than 1.")
    if x <= 0:
        raise ValueError("Logarithm is not defined for non-positive numbers.")
    return math.log(x) / math.log(base)

def sin(x):
    return math.sin(x)

def cos(x):
    return math.cos(x)

def tan(x):
    return math.tan(x)

def main():
    operations = {
        'add': add,
        'subtract': subtract,
        'multiply': multiply,
        'divide': divide,
        'factorial': factorial,
        'fibonacci': fibonacci,
        'is_prime': is_prime,
        'gcd': gcd,
        'lcm': lcm,
        'power': power,
        'sqrt': sqrt,
        'log': log,
        'sin': sin,
        'cos': cos,
        'tan': tan
    }

    while True:
        operation = input("Enter the operation (or 'exit' to quit): ").strip().lower()
        if operation == 'exit':
            break
        if operation in operations:
            try:
                if operation in ['add', 'subtract', 'multiply', 'divide', 'gcd', 'lcm', 'power', 'log']:
                    a = float(input("Enter the first value: "))
                    b = float(input("Enter the second value: "))
                    result = operations[operation](a, b)
                elif operation in ['factorial', 'fibonacci', 'is_prime']:
                    a = int(input("Enter the value: "))
                    result = operations[operation](a)
                elif operation in ['sqrt', 'log', 'sin', 'cos', 'tan']:
                    a = float(input("Enter the value: "))
                    result = operations[operation](a)
                print(f"The result is: {result}")
            except Exception as e:
                print(f"Error: {e}")
        else:
            print("Invalid operation. Please try again.")

if __name__ == "__main__":
    main()

