```python
import random
import string
from decimal import Decimal, InvalidOperation

def generate_coupon_code(length=8):
    """Generate a random coupon code of specified length."""
    if length <= 0:
        raise ValueError("Length must be a positive integer.")
    characters = string.ascii_letters + string.digits
    return ''.join(random.choice(characters) for _ in range(length))

def validate_purchase_amount(amount):
    """Validate the purchase amount."""
    try:
        amount = Decimal(amount)
        if amount <= 0:
            raise ValueError("Amount must be greater than zero.")
    except (InvalidOperation, TypeError):
        raise ValueError("Invalid amount. Please enter a valid number.")
    return amount

def apply_discount(purchase_amount, discount_percentage):
    """Apply a discount to the purchase amount."""
    try:
        discount_percentage = Decimal(discount_percentage)
        if not (0 <= discount_percentage <= 100):
            raise ValueError("Discount percentage must be between 0 and 100.")
    except (InvalidOperation, TypeError):
        raise ValueError("Invalid discount percentage. Please enter a valid number.")

    discount_amount = purchase_amount * (discount_percentage / Decimal(100))
    final_amount = purchase_amount - discount_amount
    return final_amount

def main():
    try:
        purchase_amount = input("Enter the purchase amount: ")
        amount = validate_purchase_amount(purchase_amount)

        discount_percentage = input("Enter the discount percentage: ")
        final_amount = apply_discount(amount, discount_percentage)

        coupon_code = generate_coupon_code()
        print(f"Coupon Code: {coupon_code}")
        print(f"Original Amount: ${amount:.2f}")
        print(f"Discount Applied: ${amount - final_amount:.2f}")
        print(f"Final Amount to Pay: ${final_amount:.2f}")
    except ValueError as e:
        print(f"Error: {e}")

if __name__ == "__main__":
    main()
```

