            self.policies.append(policy.strip())
        else:
            raise ValueError("Policy must be a non-empty string.")

    def implement_policies(self):
        for policy in self.policies:
            print(f"Implementing policy: {policy}")

    def display_policies(self):
        if self.policies:
            print("Current policies:")
            for idx, policy in enumerate(self.policies, 1):
                print(f"{idx}. {policy}")
        else:
            print("No policies have been set yet.")

# Example usage:
