from dataclasses import dataclass
from typing import List

@dataclass
class HistoricalFigure:
    name: str
    era: str
    notable_works: str

class DinnerParty:
    def __init__(self):
        self.guest_list: List[HistoricalFigure] = []

    def add_guest(self, guest: HistoricalFigure):
        if isinstance(guest, HistoricalFigure):
            self.guest_list.append(guest)
        else:
            raise ValueError("Guest must be an instance of HistoricalFigure")

    def list_guests(self) -> List[str]:
        return [f"{guest.name} ({guest.era}) - Notable for: {guest.notable_works}" for guest in self.guest_list]

# Example usage:
def main():
    dinner_party = DinnerParty()
    dinner_party.add_guest(HistoricalFigure("Leonardo da Vinci", "Renaissance", "Painting the Mona Lisa"))
    dinner_party.add_guest(HistoricalFigure("Marie Curie", "Late 19th - Early 20th Century", "Pioneering research on radioactivity"))
    dinner_party.add_guest(HistoricalFigure("Albert Einstein", "20th Century", "Theory of Relativity"))

    print("Dinner Party Guest List:")
    for guest_info in dinner_party.list_guests():
        print(guest_info)

if __name__ == "__main__":
    main()
```

