class GenderRolesAnalysis:
    def __init__(self):
        self.gender_roles = {
            "men": {
                "strengths": [],
                "challenges": []
            },
            "women": {
                "strengths": [],
                "challenges": []
            }
        }

    def add_gender_role_attribute(self, gender, attribute_type, attribute):
        if gender not in self.gender_roles:
            raise ValueError("Invalid gender specified.")
        if attribute_type not in ["strengths", "challenges"]:
            raise ValueError("Invalid attribute type specified.")
        self.gender_roles[gender][attribute_type].append(attribute)

    def get_gender_role_analysis(self, gender):
        if gender not in self.gender_roles:
            raise ValueError("Invalid gender specified.")
        return self.gender_roles[gender]

    def update_gender_role_attribute(self, gender, attribute_type, old_attribute, new_attribute):
        if gender not in self.gender_roles:
            raise ValueError("Invalid gender specified.")
        if attribute_type not in ["strengths", "challenges"]:
            raise ValueError("Invalid attribute type specified.")
        if old_attribute not in self.gender_roles[gender][attribute_type]:
            raise ValueError("Old attribute not found in the specified gender's attributes.")

        index = self.gender_roles[gender][attribute_type].index(old_attribute)
        self.gender_roles[gender][attribute_type][index] = new_attribute

    def delete_gender_role_attribute(self, gender, attribute_type, attribute):
        if gender not in self.gender_roles:
            raise ValueError("Invalid gender specified.")
        if attribute_type not in ["strengths", "challenges"]:
            raise ValueError("Invalid attribute type specified.")
        if attribute not in self.gender_roles[gender][attribute_type]:
            raise ValueError("Attribute not found in the specified gender's attributes.")

        self.gender_roles[gender][attribute_type].remove(attribute)
